import {createAction, createAsyncThunk} from '@reduxjs/toolkit';
import {signInWithPopup, UserInfo, signOut as firebaseSignOut} from 'firebase/auth';
import {FirebaseError} from 'firebase/app';
import {RootState} from '../store';
import {auth, provider} from '../../firebase/firebase';
import {applyBestScore, applyLatestScore, getScoreFromGoogle, trySendResultToGoogleAfterLogin} from './gameBoard.actions';

const baseType = 'GOOGLE/';

export const successSignIn = createAction<UserInfo>(`${baseType}SUCCESS_SIGN_IN`);
export const errorSignIn = createAction<FirebaseError>(`${baseType}ERROR_SIGN_IN`);
export const successSignOut = createAction(`${baseType}SUCCESS_SIGN_OUT`);
export const errorSignOut = createAction<FirebaseError>(`${baseType}ERROR_SIGN_OUT`);

export const signIn = createAsyncThunk<void, void, {state: RootState}>(`${baseType}SIGN_IN`, async (_, {dispatch}) => {
  try {
    const result = await signInWithPopup(auth, provider);
    dispatch(
      successSignIn({
        email: result.user.email,
        photoURL: result.user.photoURL,
        displayName: result.user.displayName,
        uid: result.user.uid,
        providerId: result.user.providerId,
        phoneNumber: '',
      }),
    );
    dispatch(getScoreFromGoogle());
    dispatch(trySendResultToGoogleAfterLogin());
  } catch (error) {
    dispatch(errorSignIn(error as FirebaseError));
  }
});

export const signOut = createAsyncThunk<void, void, {state: RootState}>(`${baseType}SIGN_OUT`, async (_, {dispatch}) => {
  try {
    await firebaseSignOut(auth);
    dispatch(successSignOut());
    dispatch(applyLatestScore(0));
    dispatch(applyBestScore(0));
  } catch (error) {
    dispatch(errorSignOut(error as FirebaseError));
  }
});
